content.text:
// src/styles/_tokens.scss

// Breakpoints (compile-time — used in mixin args)
$bp-sm:  640px;
$bp-md:  768px;
$bp-lg: 1024px;
$bp-xl: 1280px;

// Type scale ratio
$scale-ratio: 1.25;

// Z-index stack (enumeration)
$z-base:    10;
$z-dropdown: 100;
$z-modal:    200;
$z-toast:    300;

.nav {
  display: flex;
  gap: 8px;

  // Descendant
  &__link {                 // .nav__link — BEM modifier
    color: var(--color-text);
    text-decoration: none;

    &:hover {               // .nav__link:hover
      color: var(--color-primary);
    }

    &--active {             // .nav__link--active
      font-weight: 600;
    }
  }

  // Direct child combinator
  > li {
    list-style: none;
  }

  // Media query nesting (CSS native nesting also supports this)
  @media (max-width: 640px) {
    flex-direction: column;
  }
}

// _mixins.scss
@mixin flex-center($direction: row) {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-direction: $direction;
}

@mixin respond-to($bp) {
  @media (min-width: $bp) {
    @content;   // placeholder for caller-provided content
  }
}

@mixin visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

@mixin truncate($lines: 1) {
  @if $lines == 1 {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  } @else {
    display: -webkit-box;
    -webkit-line-clamp: $lines;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }
}

// component.scss
@use '../mixins' as m;

.hero {
  @include m.flex-center(column);

  @include m.respond-to(768px) {
    flex-direction: row;
  }
}

.sr-only {
  @include m.visually-hidden;
}

.card__title {
  @include m.truncate(2);
}

// src/styles/_tokens.scss
$primary: oklch(0.6 0.22 260);
$radius-md: 8px;

// component.scss
@use '../styles/tokens' as t;
@use 'sass:math';
@use 'sass:color';

.button {
  background-color: t.$primary;
  border-radius: t.$radius-md;
  padding: math.div(16px, 1px) + 0px;  // math operations
}

// src/styles/_index.scss
@forward 'tokens';
@forward 'mixins';
@forward 'breakpoints';

// Any component can now import everything from one place
// component.scss
@use '../styles' as s;

.hero {
  color: s.$primary;
  @include s.flex-center;
}

// _button.scss
$color: blue !default;  // default overridable by @use

// In consumer
@use 'button' with ($color: red);

@use 'sass:math';

// Fluid spacing scale — returns rem value for a step in the scale
@function space($step, $base: 4px) {
  @return $base * $step;
}

// Convert px to rem
@function rem($px, $base: 16) {
  @return math.div($px, $base) * 1rem;
}

// Usage
.card {
  padding: space(4);        // 16px
  margin-bottom: space(8);  // 32px
  font-size: rem(14);       // 0.875rem
}

$colors: (
  'primary': oklch(0.6 0.22 260),
  'danger':  oklch(0.55 0.22 30),
  'success': oklch(0.65 0.18 145),
  'warning': oklch(0.75 0.18 85),
);

@each $name, $value in $colors {
  .text-#{$name}       { color: $value; }
  .bg-#{$name}         { background-color: $value; }
  .border-#{$name}     { border-color: $value; }
}

// Generates .text-primary, .bg-primary, .text-danger, etc.

// Generate spacing utility classes: .mt-1 through .mt-8
@for $i from 1 through 8 {
  .mt-#{$i} { margin-top: #{$i * 4}px; }
  .mb-#{$i} { margin-bottom: #{$i * 4}px; }
  .p-#{$i}  { padding: #{$i * 4}px; }
}

// Staggered animation delays
@for $i from 1 through 6 {
  .list-item:nth-child(#{$i}) {
    animation-delay: #{($i - 1) * 60}ms;
  }
}

%card-base {
  border-radius: 8px;
  overflow: hidden;
  background: var(--color-surface);
}

.product-card {
  @extend %card-base;
  padding: 16px;
}

.article-card {
  @extend %card-base;
  padding: 24px;
}

/* Compiles to:
   .product-card, .article-card { border-radius: 8px; ... }
   .product-card { padding: 16px; }
   .article-card { padding: 24px; }
*/

// angular.json — expose styles/ dir for clean @use paths
{
  "build": {
    "options": {
      "stylePreprocessorOptions": {
        "includePaths": ["src/styles"]
      }
    }
  }
}

// button.component.scss — after includePaths configured
@use 'tokens' as t;
@use 'mixins' as m;
@use 'breakpoints' as bp;

:host {
  display: inline-flex;
  @include m.flex-center;
  padding: t.$space-2 t.$space-4;
  background-color: var(--color-primary);
  border-radius: var(--radius-md);
  font-size: var(--text-sm);

  @include bp.md {
    padding: t.$space-3 t.$space-6;
  }
}
